// Filter and normalize articles from all sources
const items = $input.all();
const now = new Date();
const oneDayAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000);

const processedArticles = [];
const seenUrls = new Set();

for (const item of items) {
  let article = {};

  // Handle NewsAPI response format
  if (item.json.articles && Array.isArray(item.json.articles)) {
    for (const art of item.json.articles) {
      if (!art.url || seenUrls.has(art.url)) continue;

      const pubDate = new Date(art.publishedAt);
      if (pubDate < oneDayAgo) continue;

      seenUrls.add(art.url);
      processedArticles.push({
        title: art.title || 'No title',
        description: art.description || art.content || 'No description',
        url: art.url,
        source: art.source?.name || 'NewsAPI',
        publishedAt: art.publishedAt,
        author: art.author || 'Unknown',
        urlToImage: art.urlToImage || null,
        engagement: 0
      });
    }
  }
  // Handle GNews response format
  else if (item.json.articles && Array.isArray(item.json.articles)) {
    for (const art of item.json.articles) {
      if (!art.url || seenUrls.has(art.url)) continue;

      const pubDate = new Date(art.publishedAt);
      if (pubDate < oneDayAgo) continue;

      seenUrls.add(art.url);
      processedArticles.push({
        title: art.title || 'No title',
        description: art.description || art.content || 'No description',
        url: art.url,
        source: art.source?.name || 'GNews',
        publishedAt: art.publishedAt,
        author: art.author || 'Unknown',
        urlToImage: art.image || null,
        engagement: 0
      });
    }
  }
}

// Estimate engagement based on title keywords and source
const highEngagementKeywords = [
  'breakthrough', 'revolutionary', 'announces', 'releases', 'launches', 
  'gpt', 'claude', 'gemini', 'openai', 'anthropic', 'google', 'microsoft',
  'mcp', 'api', 'model', 'new version'
];

for (const article of processedArticles) {
  let score = 0;
  const titleLower = article.title.toLowerCase();

  // Check for high-engagement keywords
  for (const keyword of highEngagementKeywords) {
    if (titleLower.includes(keyword)) score += 10;
  }

  // Boost for reputable sources
  const reputableSources = ['techcrunch', 'wired', 'the verge', 'ars technica', 'reuters', 'bloomberg'];
  if (reputableSources.some(s => article.source.toLowerCase().includes(s))) {
    score += 15;
  }

  article.engagement = score;
}

return processedArticles.map(article => ({ json: article }));

// Sort by engagement score (popularity proxy)
const items = $input.all();

const sorted = items.sort((a, b) => {
  return (b.json.engagement || 0) - (a.json.engagement || 0);
});

// Take top 10 most popular
const topPopular = sorted.slice(0, 10).map(item => ({
  json: {
    ...item.json,
    category: 'popular'
  }
}));

return topPopular;

// Sort by publication date (newest first)
const items = $input.all();

const sorted = items.sort((a, b) => {
  const dateA = new Date(a.json.publishedAt);
  const dateB = new Date(b.json.publishedAt);
  return dateB - dateA;
});

// Take top 10 newest
const topNewest = sorted.slice(0, 10).map(item => ({
  json: {
    ...item.json,
    category: 'newest'
  }
}));

return topNewest;
